import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface HourlyConsumption {
  hour: string;
  ounces: number;
}

interface HydrationData {
  dailyGoal: {
    targetOunces: number;
    currentOunces: number;
    percentage: number;
  };
  hourlyConsumption: HourlyConsumption[];
}

export default function Widget() {
  const hydrationData = response.data as HydrationData;
  const { dailyGoal, hourlyConsumption } = hydrationData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#00BFFF' }}>
              Hydration Goal
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#1F2937' }}>
              {dailyGoal.currentOunces} oz
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              of {dailyGoal.targetOunces} oz goal
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: '#00BFFF' }}>
                {dailyGoal.percentage}%
              </Typography>
            </Stack>
            <LinearProgress
              variant="determinate"
              value={dailyGoal.percentage}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#E0F7FF',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#00BFFF',
                  borderRadius: 4,
                }
              }}
            />
          </Box>

          <BarChart
            height={140}
            series={[
              {
                data: hourlyConsumption.map(d => d.ounces),
                color: '#7FFFD4',
              },
            ]}
            xAxis={[
              {
                data: hourlyConsumption.map(d => d.hour),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#6B7280',
                },
              }
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
